import { takeLatest, put, call, all } from 'redux-saga/effects';
import { signInWithPopup,signInWithEmailAndPassword } from 'firebase/auth';
import { auth, googleProvider, createUserProfileDocument, getCurrentUser} from '../../firebase/firebase.utils';
import {createUserWithEmailAndPassword } from 'firebase/auth';

import userActionTypes from "../user/user.types";
import  { SignInSuccess, SignInFailure, signOutSuccess, signOutFailure, signUpSuccess, signUpFailure } from "../user/user.actions";
import { getDoc } from '@firebase/firestore';

export function* signUpAsync ({payload :{displayName, auth, email, password}}) {
    try {
        const { user } = yield createUserWithEmailAndPassword(auth, email, password);
        const userRef = yield createUserProfileDocument(user, {displayName});
        yield put(signUpSuccess);
        const userSnapshot = yield getDoc(userRef);
        yield put(SignInSuccess({id: userSnapshot.id, ...userSnapshot.data()}))

    } catch(error) {
        yield put(signUpFailure(error))
    }
}
export function* signOutAsync () {
    try {
        yield auth.signOut();
        yield put(signOutSuccess());

    } catch (error) {
        yield put(signOutFailure(error));
    }
}

export function* isUserAuthenticated () {
    try {
        const userAuth = yield getCurrentUser();
        if (!userAuth) return;
        const userRef = yield call(createUserProfileDocument, userAuth);
        const userSnapshot = yield getDoc(userRef);
        yield put(SignInSuccess({id: userSnapshot.id, ...userSnapshot.data()}))
    } catch(error) {
        yield put(SignInFailure(error));
    }
}

export function* googleSignInAsync () {
    try {
        const { user } = yield signInWithPopup(auth, googleProvider);
        const userRef = yield call(createUserProfileDocument, user);
        const userSnapshot = yield getDoc(userRef);
        yield put(SignInSuccess({id: userSnapshot.id, ...userSnapshot.data()}))

    } catch(error) {
        yield put(SignInFailure(error));
    }  
}

export function* emailSignInAsync ({payload :{email, password}}) {
    try{
        const { user } = yield signInWithEmailAndPassword(auth, email, password);
        const userRef = yield call(createUserProfileDocument, user);
        const userSnapshot = yield getDoc(userRef);
        yield put(SignInSuccess({id: userSnapshot.id, ...userSnapshot.data()}))
    }
    catch (error) {
        yield put(SignInFailure(error));
    }
}

export function* signUpStart () {
    yield takeLatest(userActionTypes.SIGNUP_START, signUpAsync)
}
export function* onSignOutStart () {
    yield takeLatest(userActionTypes.SIGNOUT_START, signOutAsync)
}

export function* onCheckUserSession () {
    yield takeLatest(userActionTypes.CHECK_USER_SESSION, isUserAuthenticated);
}

export function* onGoogleSignInStart () {
    yield takeLatest(userActionTypes.GOOGLE_SIGNIN_START, googleSignInAsync);
}

export function* onEmailSignInStart () {
    yield takeLatest(userActionTypes.EMAIL_SIGNIN_START, emailSignInAsync)
}

export function* userSagas () {
    yield all([
        call(onGoogleSignInStart),
        call(onEmailSignInStart), 
        call(onCheckUserSession), 
        call(onSignOutStart),
        call(signUpStart)
    ])
}
